             // This check is slightly tricky because the PQ might contain multiple entries for the same cell 
             // at the same time due to different paths, but the grid already reflects the best color so far.
             // If the grid color is strictly greater, we ignore this outdated entry.
             continue;
        }


        const nextTime = time + 1;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {

                // Check the target cell's current state in the grid
                const currentColor = grid[nr][nc];

                // Case 1: Uncolored cell (currentColor === 0)
                if (currentColor === 0) {
                    // This cell is reached for the first time by color 'color' at time 'nextTime'.
                    // Since we are using a PQ prioritized by time then max color, this is the best known arrival time/color.
                    // Set the color and enqueue for expansion.
                    grid[nr][nc] = color;
                    pq.enqueue([nextTime, -color, nr, nc]);
                } 
                // Case 2: Colored cell (currentColor > 0)
                else {
                    // Check for conflict: Does the incoming color 'color' beat the existing color 'currentColor'?
                    // If color > currentColor, the new color wins according to the rule: "adopt the color with the maximum value".
                    // Since this process is simultaneous, if the new color wins, it should overwrite, and propagate.
                    if (color > currentColor) {
                        // The incoming color is better. We update the grid and enqueue this cell
                        // because its color has changed, potentially changing its future propagation.
                        grid[nr][nc] = color;
                        pq.enqueue([nextTime, -color, nr, nc]);
                    } 
                    // If color < currentColor, the existing color wins, no action needed.
                    // If color == currentColor, no action needed (already settled to this color).
                }
            }
        }
    }

    return grid;
}
